from autogen import GroupChatManager, GroupChat
def monitor_memory_growth(agents, max_tokens=8000):
    total_tokens = 0
    for agent in agents:
        if hasattr(agent, 'chat_messages'):
            for convo in agent.chat_messages.values():
                for msg in convo:
                    total_tokens += len(msg['content']) // 4  # rough token estimate
    growth_rate = total_tokens / len(agents)
    if growth_rate > max_tokens:
        print(f'⚠️ Memory overflow detected: {total_tokens} tokens')
        return False
    return True

# Usage in group chat
groupchat = GroupChat(agents=agents, messages=[], max_round=20)
manager = GroupChatManager(groupchat=groupchat)
for i in range(20):
    monitor_memory_growth(agents)

