from autogen import register_function
class MemoryManager:
    def __init__(self, max_messages=20):
        self.max_messages = max_messages
        self.message_window = []

    def add_message(self, message):
        self.message_window.append(message)
        if len(self.message_window) > self.max_messages:
            self.message_window.pop(0)
        return self.message_window[-10:]  # return recent context

    def get_context(self):
        return self.message_window

# Integrate with agent
memory_manager = MemoryManager()
def memory_filtered_reply(messages, sender, config):
    context = memory_manager.add_message({'messages': messages[-1]})
    return config['llm_client'].create(
        messages=context + messages[-1:],
        **config
    )

# Register as reply filter
agent.register_reply([memory_filtered_reply], '')

def create_summary_compressor(llm_client):
    def compress_history(messages):
        if len(messages) < 10:
            return messages

        summary_prompt = f"""Summarize this conversation in 200 tokens, preserving:\n1. Open questions\n2. Key disagreements\n3. Recent decisions\n4. Pending tasks\n\nConversation:\n{chr(10).join([f"{m['role']}: {m['content'][:100]}..." for m in messages[-15:]])}"""

        summary = llm_client.create([
            {'role': 'system', 'content': 'You are a conversation summarizer.'},
            {'role': 'user', 'content': summary_prompt}
        ]).choices[0].message.content

        return [{'role': 'system', 'content': f'Conversation summary: {summary}'}] + messages[-3:]
    return compress_history

# Usage
compressor = create_summary_compressor(llm_client)
def summary_reply_filter(messages, sender, config):
    compressed = compressor(messages)
    return config['llm_client'].create(messages=compressed, **config)

def token_budget_filter(max_tokens=4000):
    def filter_fn(messages, sender, config):
        total_tokens = sum(len(m['content']) // 4 for m in messages)

        if total_tokens > max_tokens:
            # Keep last N messages to fit budget
            tokens_per_msg = [len(m['content']) // 4 for m in messages]
            keep_count = 0
            running_total = 0

            for i, tokens in enumerate(reversed(tokens_per_msg)):
                if running_total + tokens < max_tokens * 0.9:
                    running_total += tokens
                    keep_count += 1
                else:
                    break

            messages = messages[-keep_count:] + [{
                'role': 'system',
                'content': f'Note: Context truncated to {max_tokens} tokens. Focus on most recent exchange.'
            }]

        return config['llm_client'].create(messages=messages, **config)
    return filter_fn

# Apply to agent
token_filter = token_budget_filter(4000)
agent.register_reply([token_filter], '')

