import vex
from autogen import GroupChat, GroupChatManager

# Install: pip install autogen vex-sdk

# 1. Initialize Vex with AutoGen memory policy
vex_client = vex.VexClient(
    api_key="your-vex-key",
    policies={
        "memory_management": {
            "max_tokens_per_agent": 4000,
            "loop_detection_window": 20,
            "max_growth_rate": 1.2,
            "remediations": ["truncate", "summarize"]
        }
    }
)

# 2. Register Vex as reply filter (intercepts ALL agent replies)
@vex_client.register_filter("autogen-memory")
def vex_memory_filter(messages, sender, config):
    verdict = vex_client.check("memory_management", {
        "messages": messages,
        "agent_id": sender.name,
        "token_count": sum(len(m['content']) // 4 for m in messages)
    })

    if verdict['action'] == 'truncate':
        messages = vex_client.apply_remediation('truncate_context', messages)
    elif verdict['action'] == 'summarize':
        messages = vex_client.apply_remediation('summarize_history', messages)

    # Log to Vex dashboard
    vex_client.log_conversation(sender.name, messages, verdict)
    return config['llm_client'].create(messages=messages, **config)

# 3. Apply to group chat
for agent in agents:
    agent.register_reply([vex_memory_filter], '')

# Vex now automatically prevents all memory issues
groupchat = GroupChat(agents=agents, messages=[])
manager = GroupChatManager(groupchat=groupchat)
manager.start()
